Modified greedy insertion with fallback: evaluate all existing non-empty assigns plus one potential empty assign per order using a regret-based heuristic that considers marginal time-window feasibility and distance increase, then attempt the best feasible option, otherwise create a new assign if capacity allows.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	orderCount := len(oris)
	if orderCount == 0 {
		dispatch.RenewnTotalCost()
		return dispatch
	}
	type candidate struct {
		assignIdx int
		costDelta float64
		feasible  bool
	}
	newShipIdBase := total_ship
	emptySlotUsed := false
	for oi := 0; oi < orderCount; oi++ {
		ori := oris[oi]
		des := dess[oi]
		shipId := newShipIdBase + oi
		bestCandidate := candidate{assignIdx: -1, costDelta: 1e18, feasible: false}
		secondBestDelta := 1e18
		regretValue := 0.0
		candidatesEvaluated := 0
		maxExistingAssign := dispatch.AssignsLen
		if maxExistingAssign > MAXASSIGNS {
			maxExistingAssign = MAXASSIGNS
		}
		totalSlotsToTry := maxExistingAssign + 1
		slotFeasibilityMask := make([]bool, totalSlotsToTry)
		slotDeltas := make([]float64, totalSlotsToTry)
		for slot := 0; slot < totalSlotsToTry; slot++ {
			idx := slot
			isNewEmpty := (slot == maxExistingAssign)
			if isNewEmpty {
				if emptySlotUsed || dispatch.AssignsLen >= MAXASSIGNS {
					continue
				}
			}
			testAssign := &dispatch.Assigns[idx]
			prevLen := testAssign.StationsLen
			insertOk := testAssign.AddShip(shipId, ori, des)
			var delta float64
			if insertOk {
				oldCost := testAssign.Cost
				testAssign.GenRoute()
				newCost := testAssign.Cost
				delta = newCost - oldCost
				if newCost >= 0 {
					slotFeasibilityMask[slot] = true
					slotDeltas[slot] = delta
					if delta < bestCandidate.costDelta {
						secondBestDelta = bestCandidate.costDelta
						bestCandidate.assignIdx = idx
						bestCandidate.costDelta = delta
						bestCandidate.feasible = true
					} else if delta < secondBestDelta {
						secondBestDelta = delta
					}
					candidatesEvaluated++
				} else {
					slotFeasibilityMask[slot] = false
				}
			} else {
				slotFeasibilityMask[slot] = false
			}
			if prevLen != testAssign.StationsLen || testAssign.StationsLen > 0 {
				testAssign.RemoveShip(shipId)
				testAssign.GenRoute()
			}
		}
		if candidatesEvaluated >= 2 {
			regretValue = secondBestDelta - bestCandidate.costDelta
		}
		chosenIdx := -1
		useRegretThreshold := false
		minRegretThreshold := 5000.0
		if bestCandidate.feasible {
			if candidatesEvaluated >= 2 && regretValue > minRegretThreshold {
				useRegretThreshold = true
			}
			chosenIdx = bestCandidate.assignIdx
		}
		if chosenIdx < 0 {
			for slot := 0; slot < totalSlotsToTry; slot++ {
				if slotFeasibilityMask[slot] {
					chosenIdx = slot
					break
				}
			}
		}
		success := false
		if chosenIdx >= 0 && chosenIdx < maxExistingAssign {
			targetAssign := &dispatch.Assigns[chosenIdx]
			ok := targetAssign.AddShip(shipId, ori, des)
			if ok {
				targetAssign.GenRoute()
				if targetAssign.Cost >= 0 {
					success = true
				} else {
					targetAssign.RemoveShip(shipId)
					targetAssign.GenRoute()
				}
			}
		}
		if !success && chosenIdx >= maxExistingAssign {
			if dispatch.AssignsLen < MAXASSIGNS {
				newAssignIdx := dispatch.AssignsLen
				newAssign := &dispatch.Assigns[newAssignIdx]
				ok := newAssign.AddShip(shipId, ori, des)
				if ok {
					newAssign.GenRoute()
					if newAssign.Cost >= 0 {
						dispatch.AssignsLen++
						emptySlotUsed = true
						success = true
					} else {
						newAssign.RemoveShip(shipId)
						newAssign.GenRoute()
					}
				}
			}
		}
		if !success {
			fallbackIdx := dispatch.AssignsLen
			if fallbackIdx < MAXASSIGNS {
				fbAssign := &dispatch.Assigns[fallbackIdx]
				ok := fbAssign.AddShip(shipId, ori, des)
